mapper.update:
UPDATE week_plans
SET day_of_week = #{dayOfWeek},
    title       = #{title},
    color       = #{color},
    start_time  = #{startTime},
    end_time    = #{endTime}
WHERE plan_no = #{planNo}
  AND user_uuid = #{userUuid}

mapper.delete:
DELETE FROM week_plans
WHERE plan_no = #{planNo}
  AND user_uuid = #{userUuid}
